import { useState, useEffect } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Search, Settings, Plus, Sparkles, Languages } from "lucide-react";
import { NewsFilters } from "@/components/news-filters";
import { NewsArticleCard } from "@/components/news-article-card";
import { TranslationModal } from "@/components/translation-modal";
import { StatsBar } from "@/components/stats-bar";
import { ThemeSwitcher } from "@/components/theme-switcher";
import { useTheme } from "@/contexts/theme-context";
import { useLanguage } from "@/contexts/language-context";
import type { Article, FilterState, Language } from "@shared/schema";
import type { SupportedLanguage } from "@/lib/i18n";

export default function Home() {
  const [filters, setFilters] = useState<FilterState>({
    categories: [],
    biasTypes: [],
    sentiments: [],
    timeRange: '',
    language: 'en',
    search: '',
  });
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState('latest');
  const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
  const [isTranslationModalOpen, setIsTranslationModalOpen] = useState(false);

  const { theme } = useTheme();
  const { language, setLanguage, t } = useLanguage();
  const queryClient = useQueryClient();

  const { data: languages } = useQuery<Language[]>({
    queryKey: ['/api/languages'],
  });

  const { data: articles = [], isLoading, error } = useQuery<Article[]>({
    queryKey: ['/api/articles', filters, sortBy],
    queryFn: async () => {
      const params = new URLSearchParams();

      if (filters.categories && filters.categories.length > 0) {
        filters.categories.forEach(cat => params.append('categories', cat));
      }
      if (filters.biasTypes && filters.biasTypes.length > 0) {
        filters.biasTypes.forEach(bias => params.append('biasTypes', bias));
      }
      if (filters.sentiments && filters.sentiments.length > 0) {
        filters.sentiments.forEach(sent => params.append('sentiments', sent));
      }
      if (filters.timeRange) {
        params.append('timeRange', filters.timeRange);
      }
      if (filters.search) {
        params.append('search', filters.search);
      }
      params.append('language', filters.language);

      const response = await fetch(`/api/articles?${params}`);
      if (!response.ok) {
        throw new Error('Failed to fetch articles');
      }
      return response.json();
    },
  });

  // Debounced search
  useEffect(() => {
    const timer = setTimeout(() => {
      setFilters(prev => ({ ...prev, search: searchTerm }));
    }, 500);

    return () => clearTimeout(timer);
  }, [searchTerm]);

  const handleTranslate = (article: Article) => {
    setSelectedArticle(article);
    setIsTranslationModalOpen(true);
  };

  const handleRefresh = () => {
    queryClient.invalidateQueries({ queryKey: ['/api/articles'] });
  };

  const handleLanguageChange = (language: string) => {
    setFilters(prev => ({ ...prev, language }));
  };

  if (error) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-center fade-in">
          <h1 className="text-2xl font-bold text-foreground mb-2">Error Loading News</h1>
          <p className="text-muted-foreground mb-4">Failed to fetch articles. Please try again.</p>
          <Button onClick={handleRefresh} className="hover-lift">Retry</Button>
        </div>
      </div>
    );
  }

  return (
    <div className={`min-h-screen bg-background transition-all duration-500 ${theme === 'creative' ? 'creative-bg' : ''}`}>
      {/* Header */}
      <header className="glass-morphism backdrop-blur-md border-b border-border sticky top-0 z-50 slide-in-right">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center">
              <div className="flex-shrink-0">
                <div className="flex items-center gap-2">
                  {theme === 'creative' && <Sparkles className="h-5 w-5 text-primary pulse-subtle" />}
                  <h1 className={`text-xl font-bold text-primary ${theme === 'creative' ? 'gradient-primary bg-clip-text text-transparent' : ''}`}>
                    {t.appTitle}
                  </h1>
                </div>
                <span className="text-xs text-muted-foreground">{t.appSubtitle}</span>
              </div>
            </div>

            <div className="flex-1 max-w-lg mx-8">
              <div className="relative">
                <Input
                  type="text"
                  placeholder={t.searchPlaceholder}
                  className={`pl-10 transition-all duration-200 hover-lift ${
                    theme === 'creative' ? 'glass-morphism' : ''
                  }`}
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
                <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
              </div>
            </div>

            <div className="flex items-center space-x-3">
              {/* UI Language Switcher */}
              <Select value={language} onValueChange={(value: SupportedLanguage) => setLanguage(value)}>
                <SelectTrigger className={`w-36 hover-lift ${
                  theme === 'creative' ? 'glass-morphism' : ''
                }`}>
                  <div className="flex items-center gap-2">
                    <Languages className="h-4 w-4" />
                    <SelectValue />
                  </div>
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="en">English</SelectItem>
                  <SelectItem value="hi">हिंदी</SelectItem>
                  <SelectItem value="mr">मराठी</SelectItem>
                  <SelectItem value="ta">தமிழ்</SelectItem>
                  <SelectItem value="kn">ಕನ್ನಡ</SelectItem>
                  <SelectItem value="te">తెలుగు</SelectItem>
                  <SelectItem value="ml">മലയാളം</SelectItem>
                </SelectContent>
              </Select>

              {/* Article Language Filter */}
              <Select value={filters.language} onValueChange={handleLanguageChange}>
                <SelectTrigger className={`w-40 hover-lift ${
                  theme === 'creative' ? 'glass-morphism' : ''
                }`}>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {languages?.map((language) => (
                    <SelectItem key={language.code} value={language.code}>
                      {language.nativeName}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>

              <ThemeSwitcher />

              <Button variant="ghost" size="sm" className="hover-lift">
                <Settings className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        <div className="flex flex-col lg:flex-row gap-6">
          {/* Sidebar */}
          <aside className="w-full lg:w-64 flex-shrink-0 fade-in">
            <div className="sticky top-20">
              <NewsFilters filters={filters} onFiltersChange={setFilters} />
            </div>
          </aside>

          {/* Main Content */}
          <main className="flex-1 fade-in">
            <StatsBar onRefresh={handleRefresh} sortBy={sortBy} onSortChange={setSortBy} />

            {/* Articles */}
            {isLoading ? (
              <div className="space-y-6 fade-in">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className={`bg-card rounded-lg shadow-sm p-6 animate-pulse hover-lift ${
                    theme === 'creative' ? 'glass-morphism' : ''
                  }`}>
                    <div className="flex items-center gap-2 mb-3">
                      <div className="h-4 w-16 bg-muted rounded"></div>
                      <div className="h-4 w-20 bg-muted rounded"></div>
                    </div>
                    <div className="h-6 w-3/4 bg-muted rounded mb-2"></div>
                    <div className="h-4 w-full bg-muted rounded mb-1"></div>
                    <div className="h-4 w-2/3 bg-muted rounded"></div>
                  </div>
                ))}
              </div>
            ) : articles.length === 0 ? (
              <div className={`bg-card rounded-lg shadow-sm p-8 text-center hover-lift fade-in ${
                theme === 'creative' ? 'glass-morphism' : ''
              }`}>
                <h3 className="text-lg font-medium text-foreground mb-2">{t.noArticlesFound}</h3>
                <p className="text-muted-foreground mb-4">
                  Try adjusting your filters or search terms to find more articles.
                </p>
                <Button onClick={handleRefresh} className="hover-lift">
                  {t.refresh} {t.articles}
                </Button>
              </div>
            ) : (
              <div className="space-y-6 fade-in">
                {articles.map((article, index) => (
                  <div 
                    key={article.id}
                    className="fade-in"
                    style={{
                      animationDelay: `${index * 50}ms`
                    }}
                  >
                    <NewsArticleCard
                      article={article}
                      onTranslate={handleTranslate}
                    />
                  </div>
                ))}

                {/* Load More Button */}
                <div className="flex justify-center mt-8">
                  <Button 
                    variant="outline" 
                    onClick={handleRefresh}
                    className={`hover-lift transition-all duration-300 ${
                      theme === 'creative' 
                        ? 'gradient-secondary text-secondary-foreground border-none' 
                        : ''
                    }`}
                  >
                    <Plus className="h-4 w-4 mr-2" />
                    Load More {t.articles}
                  </Button>
                </div>
              </div>
            )}
          </main>
        </div>
      </div>

      {/* Translation Modal */}
      <TranslationModal
        article={selectedArticle}
        isOpen={isTranslationModalOpen}
        onClose={() => {
          setIsTranslationModalOpen(false);
          setSelectedArticle(null);
        }}
      />

      {/* Floating Action Button */}
      <div className="fixed bottom-6 right-6 z-40 fade-in">
        <Button
          className={`w-14 h-14 rounded-full shadow-lg hover-lift float-animation transition-all duration-300 ${
            theme === 'creative' 
              ? 'gradient-primary border-none' 
              : 'bg-primary hover:bg-primary/90'
          }`}
          onClick={handleRefresh}
        >
          <Plus className="h-6 w-6" />
        </Button>
      </div>
    </div>
  );
}

